SELECT [Sales Cr_Memo Header].[Geographical Zone 2], [Sales Cr_Memo Header].[Shortcut Dimension 2 Code] AS Trademark, [Sales Cr_Memo Header].[Selling Season Code], [Sales Cr_Memo Header].[Salesperson Code], Salesperson_Purchaser.Name AS SalespersonName, [Sales Cr_Memo Header].[Sell-to Customer No_], [Sales Cr_Memo Header].[Sell-to Customer Name], [Sales Cr_Memo Header].No_, [Sales Cr_Memo Header].[Posting Date], Sum(Val([amount])) AS Importo
FROM ([Sales Cr_Memo Line] INNER JOIN [Sales Cr_Memo Header] ON [Sales Cr_Memo Line].[Document No_] = [Sales Cr_Memo Header].No_) LEFT JOIN Salesperson_Purchaser ON [Sales Cr_Memo Header].[Salesperson Code] = Salesperson_Purchaser.Code
WHERE ((([Sales Cr_Memo Line].No_)="R0100202" Or ([Sales Cr_Memo Line].No_)="R0100203" Or ([Sales Cr_Memo Line].No_)="R0100204" Or ([Sales Cr_Memo Line].No_)="R0100205"))
GROUP BY [Sales Cr_Memo Header].[Geographical Zone 2], [Sales Cr_Memo Header].[Shortcut Dimension 2 Code], [Sales Cr_Memo Header].[Selling Season Code], [Sales Cr_Memo Header].[Salesperson Code], Salesperson_Purchaser.Name, [Sales Cr_Memo Header].[Sell-to Customer No_], [Sales Cr_Memo Header].[Sell-to Customer Name], [Sales Cr_Memo Header].No_, [Sales Cr_Memo Header].[Posting Date], [Sales Cr_Memo Line].Type
HAVING ((([Sales Cr_Memo Header].[Posting Date]) Between [data iniziale] And [data finale]) AND (([Sales Cr_Memo Line].Type)=1));

